(() => {
  'use strict';
  const STORAGE_KEY='khairpur_admin_data_v1', PIN_KEY='khairpur_admin_pin_v1';
  const emptyData=()=>({version:1,orders:[],workers:[],logs:[],updatedAt:new Date().toISOString()});
  let data=load(), deleteTarget=null, cloudReady=false;
  const $=(selector,root=document)=>root.querySelector(selector), $$=(selector,root=document)=>[...root.querySelectorAll(selector)];
  const uid=()=>crypto.randomUUID();
  const cleanPhone=(value)=>String(value||'').replace(/[^0-9]/g,'');
  const esc=(value)=>String(value??'').replace(/[&<>"]/g,(char)=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[char]));
  const money=(value)=>`PKR ${new Intl.NumberFormat('en-PK',{maximumFractionDigits:0}).format(Number(value)||0)}`;
  const dateLabel=(value)=>value?new Intl.DateTimeFormat('en-PK',{day:'2-digit',month:'short',year:'numeric'}).format(new Date(`${value}T12:00:00`)):'Not set';
  function load(){try{const parsed=JSON.parse(localStorage.getItem(STORAGE_KEY));return parsed&&Array.isArray(parsed.orders)&&Array.isArray(parsed.workers)&&Array.isArray(parsed.logs)?parsed:emptyData()}catch{return emptyData()}}
  function save(){data.updatedAt=new Date().toISOString();localStorage.setItem(STORAGE_KEY,JSON.stringify(data));renderAll()}
  function log(action,detail){const item={id:uid(),action,detail,at:new Date().toISOString()};data.logs.unshift(item);data.logs=data.logs.slice(0,500);if(cloudReady)window.KhairpurCloud.addLog(item).catch(()=>{})}
  const cloudCall=async(promise,label)=>{try{const result=await promise;if(result?.error)throw result.error;return result}catch(error){alert(`${label} cloud sync failed. Local copy is saved. ${error.message||''}`);return null}};
  const toHex=(bytes)=>[...bytes].map((byte)=>byte.toString(16).padStart(2,'0')).join('');
  const fromHex=(value)=>new Uint8Array(value.match(/.{1,2}/g).map((byte)=>parseInt(byte,16)));
  async function hash(value,saltHex){const material=await crypto.subtle.importKey('raw',new TextEncoder().encode(value),'PBKDF2',false,['deriveBits']);const bits=await crypto.subtle.deriveBits({name:'PBKDF2',hash:'SHA-256',salt:fromHex(saltHex),iterations:150000},material,256);return toHex(new Uint8Array(bits))}
  async function makePinRecord(value){const salt=crypto.getRandomValues(new Uint8Array(16));const saltHex=toHex(salt);return JSON.stringify({salt:saltHex,hash:await hash(value,saltHex),iterations:150000})}

  const accessScreen=$('#access-screen'),app=$('#admin-app'),accessCopy=$('#access-copy'),accessForm=$('#access-form'),accessPin=$('#access-pin'),accessStatus=$('#access-status');
  const hasPin=()=>Boolean(localStorage.getItem(PIN_KEY));
  function showAdmin(){sessionStorage.setItem('khairpur_admin_unlocked','1');accessScreen.hidden=true;app.hidden=false;renderAll()}
  function lockAdmin(){sessionStorage.removeItem('khairpur_admin_unlocked');app.hidden=true;accessScreen.hidden=false;accessPin.value='';accessCopy.textContent='Enter the device PIN to open private business records.';accessPin.focus()}
  if(hasPin())accessCopy.textContent='Enter the device PIN to open private business records.';
  if(hasPin()&&sessionStorage.getItem('khairpur_admin_unlocked')==='1')showAdmin();
  accessForm.addEventListener('submit',async(event)=>{event.preventDefault();const pin=accessPin.value.trim();if(!/^\d{6,12}$/.test(pin)){accessStatus.textContent='Use a 6–12 digit PIN.';return}if(!hasPin()){localStorage.setItem(PIN_KEY,await makePinRecord(pin));log('Security','Device PIN created');save();showAdmin();return}try{const record=JSON.parse(localStorage.getItem(PIN_KEY));const digest=await hash(pin,record.salt);if(digest===record.hash){accessStatus.textContent='';showAdmin()}else accessStatus.textContent='Incorrect PIN.'}catch{accessStatus.textContent='PIN record is damaged. Restore browser data or reset this workspace.'}});
  $('#lock-admin').addEventListener('click',lockAdmin);

  const inviteScreen=$('#invite-screen'),inviteEmail=$('#invite-email'),inviteForm=$('#invite-form'),invitePassword=$('#invite-password'),invitePasswordConfirm=$('#invite-password-confirm'),inviteStatus=$('#invite-status');
  function showInviteScreen(session){accessScreen.hidden=true;inviteScreen.hidden=false;inviteEmail.textContent=session?.user?.email||'your account'}
  const isInviteOrRecoveryLink=window.KHAIRPUR_AUTH_HASH_TYPE==='invite'||window.KHAIRPUR_AUTH_HASH_TYPE==='recovery';
  if(window.KhairpurCloud){
    window.KhairpurCloud.client.auth.onAuthStateChange((event,session)=>{if(event==='PASSWORD_RECOVERY'||(event==='SIGNED_IN'&&isInviteOrRecoveryLink))showInviteScreen(session)});
  }
  inviteForm?.addEventListener('submit',async(event)=>{
    event.preventDefault();
    if(invitePassword.value.length<8){inviteStatus.textContent='Password must be at least 8 characters.';return}
    if(invitePassword.value!==invitePasswordConfirm.value){inviteStatus.textContent='Passwords do not match.';return}
    inviteStatus.textContent='Saving password…';
    const{error}=await window.KhairpurCloud.client.auth.updateUser({password:invitePassword.value});
    if(error){inviteStatus.textContent=`Could not set password: ${error.message}`;return}
    inviteStatus.textContent='Password set. You can now sign in from Backup & Settings → Admin cloud login.';
    setTimeout(()=>{inviteScreen.hidden=true;accessScreen.hidden=false},2000);
  });

  const titles={dashboard:'Business overview',orders:'Orders & leads',workers:'Worker directory',media:'Pictures & videos',logs:'Activity history',settings:'Backup & settings'};
  function switchView(name){$$('.nav-item').forEach((item)=>item.classList.toggle('active',item.dataset.view===name));$$('.admin-view').forEach((panel)=>panel.classList.toggle('active',panel.dataset.viewPanel===name));$('#view-title').textContent=titles[name];$('.sidebar').classList.remove('open');scrollTo({top:0,behavior:'smooth'})}
  $$('.nav-item').forEach((button)=>button.addEventListener('click',()=>switchView(button.dataset.view)));
  $$('[data-view-link]').forEach((button)=>button.addEventListener('click',()=>switchView(button.dataset.viewLink)));
  $('.sidebar-toggle').addEventListener('click',()=>$('.sidebar').classList.toggle('open'));
  $('#today').textContent=new Intl.DateTimeFormat('en-PK',{weekday:'long',day:'numeric',month:'long'}).format(new Date());

  const orderDialog=$('#order-dialog'),orderForm=$('#order-form'),workerDialog=$('#worker-dialog'),workerForm=$('#worker-form'),mediaDialog=$('#media-dialog'),mediaForm=$('#media-form'),confirmDialog=$('#confirm-dialog');
  const resetForm=(form)=>{form.reset();form.elements.id.value=''};
  function openOrder(id){resetForm(orderForm);$('#order-dialog-title').textContent=id?'Edit order or lead':'Add order or lead';if(id){const record=data.orders.find((item)=>item.id===id);if(!record)return;Object.entries(record).forEach(([key,value])=>{if(orderForm.elements[key])orderForm.elements[key].value=value??''})}orderDialog.showModal()}
  function openWorker(id){resetForm(workerForm);$('#worker-dialog-title').textContent=id?'Edit worker':'Add worker';if(id){const record=data.workers.find((item)=>item.id===id);if(!record)return;Object.entries(record).forEach(([key,value])=>{if(workerForm.elements[key])workerForm.elements[key].value=value??''})}workerDialog.showModal()}
  $$('[data-open-order]').forEach((button)=>button.addEventListener('click',()=>openOrder()));
  $$('[data-open-worker]').forEach((button)=>button.addEventListener('click',()=>openWorker()));
  $$('[data-open-media]').forEach((button)=>button.addEventListener('click',()=>{mediaForm.reset();$('#upload-status').textContent='';mediaDialog.showModal()}));
  orderForm.addEventListener('submit',async(event)=>{event.preventDefault();if(event.submitter?.value==='cancel'){orderDialog.close();return}if(!orderForm.reportValidity())return;const values=Object.fromEntries(new FormData(orderForm)),now=new Date().toISOString();let record;if(values.id){const index=data.orders.findIndex(item=>item.id===values.id);record=data.orders[index]={...data.orders[index],...values,amount:Number(values.amount)||0,updatedAt:now};log('Order updated',`${values.customer} — ${values.product}`)}else{values.id=uid();values.amount=Number(values.amount)||0;values.createdAt=now;values.updatedAt=now;record=values;data.orders.unshift(record);log('Order added',`${values.customer} — ${values.product}`)}save();if(cloudReady)await cloudCall(KhairpurCloud.saveOrder(record),'Order');orderDialog.close()});
  workerForm.addEventListener('submit',async(event)=>{event.preventDefault();if(event.submitter?.value==='cancel'){workerDialog.close();return}if(!workerForm.reportValidity())return;const values=Object.fromEntries(new FormData(workerForm)),now=new Date().toISOString();let record;if(values.id){const index=data.workers.findIndex(item=>item.id===values.id);record=data.workers[index]={...data.workers[index],...values,updatedAt:now};log('Worker updated',`${values.name} — ${values.role}`)}else{values.id=uid();values.createdAt=now;values.updatedAt=now;record=values;data.workers.unshift(record);log('Worker added',`${values.name} — ${values.role}`)}save();if(cloudReady)await cloudCall(KhairpurCloud.saveWorker(record),'Worker');workerDialog.close()});
  mediaForm.addEventListener('submit',async(event)=>{event.preventDefault();if(event.submitter?.value==='cancel'){mediaDialog.close();return}if(!mediaForm.reportValidity())return;const file=mediaForm.elements.file.files[0],status=$('#upload-status'),allowed=['image/jpeg','image/png','image/webp','video/mp4','video/webm'];if(!file||!allowed.includes(file.type)){status.textContent='Please select a supported JPG, PNG, WebP, MP4 or WebM file.';return}const type=file.type.startsWith('video/')?'video':'image',limit=type==='video'?100*1024*1024:12*1024*1024;if(file.size>limit){status.textContent=`${type==='video'?'Video':'Image'} is too large. Maximum ${type==='video'?'100 MB':'12 MB'}.`;return}status.textContent='Saving media…';const record={id:uid(),title:mediaForm.elements.title.value.trim(),category:mediaForm.elements.category.value,description:mediaForm.elements.description.value.trim(),published:mediaForm.elements.published.checked,type,mime:file.type,size:file.size,filename:file.name,blob:file,createdAt:new Date().toISOString()};try{if(cloudReady)await KhairpurCloud.uploadMedia(record,file);else await MediaDB.put(record);log('Media uploaded',`${record.title} — ${record.published?'Published':'Draft'}`);save();await renderMedia();mediaDialog.close()}catch(error){status.textContent=`Upload failed: ${error.message||'Please try again.'}`}});
  function requestDelete(type,id,label,record=null){deleteTarget={type,id,label,record};confirmDialog.showModal()}
  confirmDialog.addEventListener('close',async()=>{if(confirmDialog.returnValue!=='confirm'||!deleteTarget)return;if(deleteTarget.type==='media'){if(cloudReady)await cloudCall(KhairpurCloud.deleteMedia(deleteTarget.record),'Media');else await MediaDB.remove(deleteTarget.id);log('Media deleted',deleteTarget.label);deleteTarget=null;save();await renderMedia();return}const list=deleteTarget.type==='order'?'orders':'workers',id=deleteTarget.id,type=deleteTarget.type;data[list]=data[list].filter(item=>item.id!==id);if(cloudReady)await cloudCall(type==='order'?KhairpurCloud.deleteOrder(id):KhairpurCloud.deleteWorker(id),type==='order'?'Order':'Worker');log(`${type==='order'?'Order':'Worker'} deleted`,deleteTarget.label);deleteTarget=null;save()});

  function statusClass(status){return status.toLowerCase().replaceAll(' ','-')}
  function filteredOrders(){const query=$('#order-search').value.toLowerCase().trim(),filter=$('#order-filter').value;return data.orders.filter((item)=>(filter==='all'||item.status===filter)&&[item.customer,item.phone,item.city,item.product,item.type].join(' ').toLowerCase().includes(query))}
  function renderOrders(){const records=filteredOrders(),body=$('#orders-body');body.innerHTML=records.map((item)=>`<tr><td><strong>${esc(item.customer)}</strong><small><a href="https://wa.me/${cleanPhone(item.phone)}" target="_blank" rel="noopener">${esc(item.phone)}</a> • ${esc(item.city||'No city')}</small></td><td><strong>${esc(item.product)}</strong><small>${esc(item.type)}${item.quantity?` • ${esc(item.quantity)}`:''}</small></td><td><span class="status ${statusClass(item.status)}">${esc(item.status)}</span></td><td>${esc(dateLabel(item.followup))}</td><td>${esc(money(item.amount))}</td><td><div class="row-actions"><button class="icon-action" data-edit-order="${item.id}" aria-label="Edit ${esc(item.customer)}">✎</button><button class="icon-action danger" data-delete-order="${item.id}" aria-label="Delete ${esc(item.customer)}">×</button></div></td></tr>`).join('');$('#orders-empty').hidden=records.length>0;$$('[data-edit-order]',body).forEach((button)=>button.onclick=()=>openOrder(button.dataset.editOrder));$$('[data-delete-order]',body).forEach((button)=>button.onclick=()=>{const item=data.orders.find((row)=>row.id===button.dataset.deleteOrder);requestDelete('order',item.id,`${item.customer} — ${item.product}`)})}
  $('#order-search').addEventListener('input',renderOrders);$('#order-filter').addEventListener('change',renderOrders);
  function filteredWorkers(){const query=$('#worker-search').value.toLowerCase().trim(),filter=$('#worker-filter').value;return data.workers.filter((item)=>(filter==='all'||item.status===filter)&&[item.name,item.phone,item.role,item.area].join(' ').toLowerCase().includes(query))}
  function renderWorkers(){const records=filteredWorkers(),grid=$('#worker-grid');grid.innerHTML=records.map((item)=>`<article class="worker-card"><header><span class="worker-avatar">${esc(item.name.charAt(0).toUpperCase())}</span><span class="status ${statusClass(item.status)}">${esc(item.status)}</span></header><h2>${esc(item.name)}</h2><span class="role">${esc(item.role)}</span><div class="worker-details"><a href="tel:${cleanPhone(item.phone)}">☎ ${esc(item.phone)}</a><span>Area: ${esc(item.area||'Not recorded')}</span><span>Emergency: ${esc(item.emergency||'Not recorded')}</span><span>Joined: ${esc(dateLabel(item.joined))}</span></div><footer><button data-edit-worker="${item.id}">Edit details</button><button class="danger-text" data-delete-worker="${item.id}">Remove</button></footer></article>`).join('');$('#workers-empty').hidden=records.length>0;$$('[data-edit-worker]',grid).forEach((button)=>button.onclick=()=>openWorker(button.dataset.editWorker));$$('[data-delete-worker]',grid).forEach((button)=>button.onclick=()=>{const item=data.workers.find((row)=>row.id===button.dataset.deleteWorker);requestDelete('worker',item.id,`${item.name} — ${item.role}`)})}
  $('#worker-search').addEventListener('input',renderWorkers);$('#worker-filter').addEventListener('change',renderWorkers);
  let mediaUrls=[];
  async function renderMedia(){mediaUrls.forEach(url=>URL.revokeObjectURL(url));mediaUrls=[];const query=$('#media-search').value.toLowerCase().trim(),filter=$('#media-filter').value,raw=cloudReady?await KhairpurCloud.allMedia():await MediaDB.all(),all=raw.map(item=>cloudReady?{...item,type:item.media_type,size:item.size_bytes,src:item.public_url,createdAt:item.created_at}:item).sort((a,b)=>b.createdAt.localeCompare(a.createdAt)),records=all.filter(item=>[item.title,item.category,item.description].join(' ').toLowerCase().includes(query)&&(filter==='all'||filter===item.type||(filter==='published'&&item.published)||(filter==='draft'&&!item.published))),grid=$('#admin-media-grid');grid.innerHTML=records.map(item=>{const src=cloudReady?item.src:URL.createObjectURL(item.blob);if(!cloudReady)mediaUrls.push(src);return `<article class="admin-media-card"><div class="admin-media-preview">${item.type==='video'?`<video src="${src}" controls preload="metadata"></video>`:`<img src="${src}" alt="${esc(item.title)}">`}<span class="media-type">${esc(item.type)}</span></div><div class="admin-media-copy"><h3>${esc(item.title)}</h3><p>${esc(item.category)} • ${(item.size/1024/1024).toFixed(1)} MB</p><footer><span class="status ${item.published?'media-published':'media-draft'}">${item.published?'Published':'Draft'}</span><div><button data-toggle-media="${item.id}">${item.published?'Unpublish':'Publish'}</button><button data-delete-media="${item.id}">Delete</button></div></footer></div></article>`}).join('');$('#media-empty').hidden=records.length>0;$$('[data-toggle-media]',grid).forEach(button=>button.onclick=async()=>{const item=all.find(record=>record.id===button.dataset.toggleMedia);item.published=!item.published;if(cloudReady)await cloudCall(KhairpurCloud.setMediaPublished(item.id,item.published),'Media status');else await MediaDB.put(item);log('Media status changed',`${item.title} — ${item.published?'Published':'Draft'}`);save();renderMedia()});$$('[data-delete-media]',grid).forEach(button=>button.onclick=()=>{const item=all.find(record=>record.id===button.dataset.deleteMedia);requestDelete('media',item.id,item.title,item)})}
  $('#media-search').addEventListener('input',renderMedia);$('#media-filter').addEventListener('change',renderMedia);
  function logMarkup(items){return items.map((item)=>`<div class="activity-item"><strong>${esc(item.action)} — ${esc(item.detail)}</strong><span>${new Intl.DateTimeFormat('en-PK',{dateStyle:'medium',timeStyle:'short'}).format(new Date(item.at))}</span></div>`).join('')}
  function renderLogs(){$('#recent-logs').innerHTML=data.logs.length?logMarkup(data.logs.slice(0,5)):'No activity recorded.';$('#recent-logs').classList.toggle('empty-state',!data.logs.length);$('#all-logs').innerHTML=logMarkup(data.logs);$('#logs-empty').hidden=data.logs.length>0}
  function renderDashboard(){const active=data.orders.filter((item)=>!['Completed','Lost'].includes(item.status)),today=new Date().toISOString().slice(0,10),due=active.filter((item)=>item.followup&&item.followup<=today);$('#metric-open').textContent=active.length;$('#metric-followups').textContent=due.length;$('#metric-value').textContent=money(data.orders.filter((item)=>['Confirmed','In progress','Delivered'].includes(item.status)).reduce((sum,item)=>sum+(Number(item.amount)||0),0));$('#metric-workers').textContent=data.workers.filter((item)=>item.status==='Active').length;$('#followup-list').innerHTML=due.length?due.sort((a,b)=>a.followup.localeCompare(b.followup)).slice(0,6).map((item)=>`<div class="record-row"><div><strong>${esc(item.customer)} — ${esc(item.product)}</strong><small>${esc(item.phone)} • ${esc(item.city||'No city')}</small></div><time>${esc(dateLabel(item.followup))}</time></div>`).join(''):'No follow-ups due.';$('#followup-list').classList.toggle('empty-state',!due.length)}
  function renderAll(){renderOrders();renderWorkers();renderLogs();renderDashboard();renderMedia()}

  function download(name,content,type='application/json'){const blob=new Blob([content],{type}),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=name;link.click();setTimeout(()=>URL.revokeObjectURL(url),1000)}
  function csv(rows,columns){const quote=(value)=>`"${String(value??'').replaceAll('"','""')}"`;return [columns.map(([label])=>quote(label)).join(','),...rows.map((row)=>columns.map(([,key])=>quote(row[key])).join(','))].join('\n')}
  $('#export-backup').onclick=()=>{log('Backup exported',`${data.orders.length} orders, ${data.workers.length} workers`);save();download(`khairpur-admin-backup-${new Date().toISOString().slice(0,10)}.json`,JSON.stringify(data,null,2))};
  $('#export-orders').onclick=()=>{log('Orders CSV exported',`${data.orders.length} records`);save();download('khairpur-orders.csv',csv(data.orders,[['Customer','customer'],['Phone','phone'],['City','city'],['Type','type'],['Product','product'],['Quantity','quantity'],['Amount PKR','amount'],['Status','status'],['Follow-up','followup'],['Notes','notes']]),'text/csv;charset=utf-8')};
  $('#export-workers').onclick=()=>{log('Workers CSV exported',`${data.workers.length} records`);save();download('khairpur-workers.csv',csv(data.workers,[['Name','name'],['Phone','phone'],['Role','role'],['Area','area'],['Joined','joined'],['Status','status'],['Emergency','emergency'],['Notes','notes']]),'text/csv;charset=utf-8')};
  $('#import-backup').addEventListener('change',async(event)=>{const file=event.target.files[0];if(!file)return;try{const incoming=JSON.parse(await file.text());if(!incoming||!Array.isArray(incoming.orders)||!Array.isArray(incoming.workers)||!Array.isArray(incoming.logs))throw new Error('Invalid');data=incoming;log('Backup restored',file.name);save();alert('Backup restored successfully.')}catch{alert('This is not a valid Khairpur Admin backup.')}event.target.value=''});
  $('#change-pin').onclick=()=>{const next=prompt('Enter a new 6–12 digit device PIN:');if(!next)return;if(!/^\d{6,12}$/.test(next)){alert('PIN must contain 6–12 digits.');return}makePinRecord(next).then((record)=>{localStorage.setItem(PIN_KEY,record);log('Security','Device PIN changed');save();alert('Device PIN updated.')})};
  const cloudForm=$('#cloud-auth-form'),cloudStatus=$('#cloud-auth-status'),cloudSignout=$('#cloud-signout');
  const validUuid=(value)=>/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(value);
  async function syncCloud(){cloudStatus.textContent='Syncing local records to Supabase…';for(const item of data.orders){if(!validUuid(item.id))item.id=crypto.randomUUID();const result=await window.KhairpurCloud.saveOrder(item);if(result.error)throw result.error}for(const item of data.workers){if(!validUuid(item.id))item.id=crypto.randomUUID();const result=await window.KhairpurCloud.saveWorker(item);if(result.error)throw result.error}for(const item of data.logs){if(!validUuid(item.id))item.id=crypto.randomUUID();const result=await window.KhairpurCloud.addLog(item);if(result.error)throw result.error}const remote=await window.KhairpurCloud.loadBusinessData();data.orders=remote.orders;data.workers=remote.workers;data.logs=remote.logs;cloudReady=true;save();cloudStatus.textContent='Cloud connected. Orders, workers, logs and media are syncing.';cloudForm.hidden=true;cloudSignout.hidden=false;renderMedia()}
  async function refreshCloud(){if(!window.KhairpurCloud){cloudStatus.textContent='Supabase is not ready. Check the project URL, anon key, and internet connection.';return}const session=await window.KhairpurCloud.session();if(session){try{await syncCloud()}catch(error){cloudStatus.textContent=`Cloud sync error: ${error.message}`}}}
  cloudForm.addEventListener('submit',async(event)=>{event.preventDefault();if(!window.KhairpurCloud){cloudStatus.textContent='Supabase is not ready. Check the project URL, anon key, and internet connection.';return}cloudStatus.textContent='Signing in…';const values=Object.fromEntries(new FormData(cloudForm)),result=await window.KhairpurCloud.signIn(values.email,values.password);if(result.error){cloudStatus.textContent=result.error.message;return}cloudForm.reset();try{await syncCloud()}catch(error){cloudStatus.textContent=`Cloud sync error: ${error.message}`}});
  cloudSignout.addEventListener('click',async()=>{if(window.KhairpurCloud)await window.KhairpurCloud.signOut();cloudReady=false;cloudForm.hidden=false;cloudSignout.hidden=true;cloudStatus.textContent='Signed out. Local device records remain available.';renderAll()});
  refreshCloud();
  $('#global-search').onclick=()=>{switchView('orders');$('#order-search').focus()};
})();
